const{execSync:execSync}=require("child_process"),fs=require("fs"),path=require("path");function main(){try{const e=execSync("cargo run --bin forgemax -- --help",{cwd:path.resolve(__dirname,"../../"),encoding:"utf-8"});fs.writeFileSync(path.resolve(__dirname,"../docs/cli-help.txt"),e),console.log("CLI help written to docs/cli-help.txt")}catch(e){console.error("Failed to generate CLI help:",e)}}main();